PyTypeObject* DoInitWrapperCharacter(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperCharacterType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperCharacterPyMethodDefs;
	PyType->tp_getset = FUPyWrapperCharacterGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperCharacter(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(ACharacter::StaticClass(), DoInitWrapperCharacter);
}

FUPyWrapperCharacter* UPyIsCharacter(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperCharacterType))
	{
		return (FUPyWrapperCharacter*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, ACharacter*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperCharacter* PyCharacter = UPyIsCharacter(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PyCharacter))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PyCharacter->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'ACharacter'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
